# Database setup
DATABASE = 'performance_app.db'


def init_db():
    with closing(sqlite3.connect(DATABASE)) as conn:
        with closing(conn.cursor()) as cursor:
            cursor.execute('''
                CREATE TABLE IF NOT EXISTS users (
                    id INTEGER PRIMARY KEY AUTOINCREMENT,
                    username TEXT NOT NULL,
                    email TEXT NOT NULL,
                    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
                )
            ''')
            cursor.execute('''
                CREATE TABLE IF NOT EXISTS orders (
                    id INTEGER PRIMARY KEY AUTOINCREMENT,
                    user_id INTEGER,
                    product_name TEXT,
                    amount REAL,
                    status TEXT,
                    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
                    FOREIGN KEY (user_id) REFERENCES users(id)
                )
            ''')
            conn.commit()


def get_db_connection():
    conn = sqlite3.connect(DATABASE)
    conn.row_factory = sqlite3.Row
    elasticapm.instrument()
    return conn


@app.before_request
def before_request():
    elasticapm.set_transaction_name(f'{request.method} {request.path}')
    elasticapm.set_custom_context({
        'request_id': request.headers.get('X-Request-ID', 'N/A'),
        'user_agent': request.headers.get('User-Agent', 'N/A'),
        'ip_address': request.remote_addr
    })
    elasticapm.set_user_context(
        username=request.headers.get('X-User-Name', 'anonymous'),
        email=request.headers.get('X-User-Email', ''),
        user_id=request.headers.get('X-User-ID', '')
    )


@app.route('/health', methods=['GET'])
def health_check():
    with capture_span('health_check', span_type='app'):
        return jsonify({'status': 'healthy', 'timestamp': time.time()})


@app.route('/api/users', methods=['POST'])
def create_user():
    data = request.get_json()
    
    # Add custom context
    elasticapm.set_custom_context({'user_data': data})
    
    with capture_span('validate_user_data', span_type='app.validation'):
        if not data or 'username' not in data or 'email' not in data:
            elasticapm.set_transaction_outcome('failure')
            return jsonify({'error': 'Invalid user data'}), 400
    
    with capture_span('insert_user', span_type='db.sqlite.query'):
        try:
            conn = get_db_connection()
            cursor = conn.cursor()
            cursor.execute(
                'INSERT INTO users (username, email) VALUES (?, ?)',
                (data['username'], data['email'])
            )
            user_id = cursor.lastrowid
            conn.commit()
            conn.close()
            
            elasticapm.set_transaction_outcome('success')
            elasticapm.label(user_id=user_id, action='user_created')
            
            return jsonify({'id': user_id, 'username': data['username'], 'email': data['email']}), 201
        except Exception as e:
            elasticapm.capture_exception()
            elasticapm.set_transaction_outcome('failure')
            return jsonify({'error': str(e)}), 500


@app.route('/api/users/<int:user_id>', methods=['GET'])
def get_user(user_id):
    with capture_span('fetch_user', span_type='db.sqlite.query'):
        try:
            conn = get_db_connection()
            cursor = conn.cursor()
            cursor.execute('SELECT * FROM users WHERE id = ?', (user_id,))
            user = cursor.fetchone()
            conn.close()
            
            if user:
                elasticapm.set_transaction_outcome('success')
                return jsonify(dict(user))
            else:
                elasticapm.set_transaction_outcome('failure')
                return jsonify({'error': 'User not found'}), 404
        except Exception as e:
            elasticapm.capture_exception()
            elasticapm.set_transaction_outcome('failure')
            return jsonify({'error': str(e)}), 500


