@app.route('/api/orders', methods=['POST'])
def create_order():
    data = request.get_json()
    
    with capture_span('validate_order_data', span_type='app.validation'):
        required_fields = ['user_id', 'product_name', 'amount']
        if not data or not all(field in data for field in required_fields):
            elasticapm.set_transaction_outcome('failure')
            return jsonify({'error': 'Invalid order data'}), 400
    
    with capture_span('check_user_exists', span_type='db.sqlite.query'):
        conn = get_db_connection()
        cursor = conn.cursor()
        cursor.execute('SELECT id FROM users WHERE id = ?', (data['user_id'],))
        user = cursor.fetchone()
        
        if not user:
            conn.close()
            elasticapm.set_transaction_outcome('failure')
            return jsonify({'error': 'User not found'}), 404
    
    with capture_span('process_payment', span_type='app.payment'):
        time.sleep(random.uniform(0.1, 0.3))
        payment_successful = random.random() > 0.1
    
    if payment_successful:
        with capture_span('insert_order', span_type='db.sqlite.query'):
            try:
                cursor.execute(
                    'INSERT INTO orders (user_id, product_name, amount, status) VALUES (?, ?, ?, ?)',
                    (data['user_id'], data['product_name'], data['amount'], 'completed')
                )
                order_id = cursor.lastrowid
                conn.commit()
                conn.close()
                
                elasticapm.set_transaction_outcome('success')
                elasticapm.label(order_id=order_id, status='completed', amount=data['amount'])
                
                return jsonify({
                    'id': order_id,
                    'user_id': data['user_id'],
                    'product_name': data['product_name'],
                    'amount': data['amount'],
                    'status': 'completed'
                }), 201
            except Exception as e:
                conn.close()
                elasticapm.capture_exception()
                elasticapm.set_transaction_outcome('failure')
                return jsonify({'error': str(e)}), 500
    else:
        conn.close()
        elasticapm.set_transaction_outcome('failure')
        elasticapm.label(status='payment_failed')
        return jsonify({'error': 'Payment processing failed'}), 400


@app.route('/api/orders/<int:user_id>', methods=['GET'])
def get_user_orders(user_id):
    with capture_span('fetch_user_orders', span_type='db.sqlite.query'):
        try:
            conn = get_db_connection()
            cursor = conn.cursor()
            cursor.execute('''
                SELECT o.*, u.username, u.email 
                FROM orders o
                JOIN users u ON o.user_id = u.id
                WHERE o.user_id = ?
                ORDER BY o.created_at DESC
            ''', (user_id,))
            orders = cursor.fetchall()
            conn.close()
            
            elasticapm.set_transaction_outcome('success')
            elasticapm.label(count=len(orders), user_id=user_id)
            
            return jsonify([dict(order) for order in orders])
        except Exception as e:
            elasticapm.capture_exception()
            elasticapm.set_transaction_outcome('failure')
            return jsonify({'error': str(e)}), 500


@app.route('/api/slow-endpoint', methods=['GET'])
def slow_endpoint():
    with capture_span('slow_operation_1', span_type='app.computation'):
        time.sleep(0.5)
        result1 = sum(range(1000000))
    
    with capture_span('slow_operation_2', span_type='app.computation'):
        time.sleep(0.3)
        result2 = sum(range(500000))
    
    with capture_span('database_intensive', span_type='db.sqlite.query'):
        conn = get_db_connection()
        cursor = conn.cursor()
        cursor.execute('SELECT COUNT(*) as count FROM users')
        user_count = cursor.fetchone()['count']
        
        cursor.execute('SELECT COUNT(*) as count FROM orders')
        order_count = cursor.fetchone()['count']
        conn.close()
    
    elasticapm.set_transaction_outcome('success')
    elasticapm.label(computation_result=result1 + result2)
    
    return jsonify({
        'message': 'Slow operation completed',
        'user_count': user_count,
        'order_count': order_count,
        'computation': result1 + result2
    })


@app.route('/api/error-endpoint', methods=['GET'])
def error_endpoint():
    error_type = request.args.get('type', 'generic')
    
    elasticapm.set_custom_context({'error_type': error_type})
    
    try:
        if error_type == 'division':
            with capture_span('division_error', span_type='app.computation'):
                result = 1 / 0
        elif error_type == 'index':
            with capture_span('index_error', span_type='app.computation'):
                my_list = [1, 2, 3]
                value = my_list[10]
        elif error_type == 'database':
            with capture_span('database_error', span_type='db.sqlite.query'):
                conn = get_db_connection()
                cursor = conn.cursor()
                cursor.execute('SELECT * FROM non_existent_table')
        else:
            raise Exception('Generic error triggered')
    except Exception as e:
        elasticapm.capture_exception()
        elasticapm.set_transaction_outcome('failure')
        return jsonify({'error': str(e), 'type': type(e).__name__}), 500


@app.route('/api/analytics', methods=['GET'])
def analytics():
    with capture_span('complex_analytics', span_type='app.analytics'):
        with capture_span('fetch_user_stats', span_type='db.sqlite.query'):
            conn = get_db_connection()
            cursor = conn.cursor()
            cursor.execute('''
                SELECT 
                    COUNT(*) as total_users,
                    DATE(created_at) as signup_date
                FROM users
                GROUP BY DATE(created_at)
                ORDER BY signup_date DESC
                LIMIT 30
            ''')
            user_stats = cursor.fetchall()
        
        with capture_span('fetch_order_stats', span_type='db.sqlite.query'):
            cursor.execute('''
                SELECT 
                    COUNT(*) as total_orders,
                    SUM(amount) as total_revenue,
                    AVG(amount) as avg_order_value,
                    status
                FROM orders
                GROUP BY status
            ''')
            order_stats = cursor.fetchall()
        
        with capture_span('fetch_top_users', span_type='db.sqlite.query'):
            cursor.execute('''
                SELECT 
                    u.id,
                    u.username,
                    u.email,
                    COUNT(o.id) as order_count,
                    SUM(o.amount) as total_spent
                FROM users u
                LEFT JOIN orders o ON u.id = o.user_id
                GROUP BY u.id, u.username, u.email
                ORDER BY total_spent DESC
                LIMIT 10
            ''')
            top_users = cursor.fetchall()
        
        conn.close()
        
        with capture_span('process_analytics_data', span_type='app.computation'):
            time.sleep(0.2)
            analytics_data = {
                'user_stats': [dict(row) for row in user_stats],
                'order_stats': [dict(row) for row in order_stats],
                'top_users': [dict(row) for row in top_users]
            }
    
    elasticapm.set_transaction_outcome('success')
    elasticapm.label(
        user_stats_count=len(user_stats),
        order_stats_count=len(order_stats),
        top_users_count=len(top_users)
    )
    
    return jsonify(analytics_data)


@app.errorhandler(404)
def not_found(error):
    elasticapm.set_transaction_outcome('failure')
    return jsonify({'error': 'Endpoint not found'}), 404


@app.errorhandler(500)
def internal_error(error):
    elasticapm.capture_exception()
    elasticapm.set_transaction_outcome('failure')
    return jsonify({'error': 'Internal server error'}), 500


@elasticapm.capture_span('custom_background_task', span_type='task')
def custom_background_task(task_name, duration):
    time.sleep(duration)
    elasticapm.label(task_name=task_name, duration=duration)
    return f"Task {task_name} completed in {duration}s"


@app.route('/api/background-task', methods=['POST'])
def trigger_background_task():
    data = request.get_json()
    task_name = data.get('task_name', 'default_task')
    duration = data.get('duration', 1.0)
    
    result = custom_background_task(task_name, duration)
    
    elasticapm.set_transaction_outcome('success')
    return jsonify({'result': result})


